```{.r .cell-code}
tickers <- c("QLYS", "CVLT", "PCTY", "LGND", "PCRX", "SUPN", "ABCB", "EGBN", "GSBC", "LKFN", "NBHC", "SEIC", "UCBI", "SMP", "GNTX", "FND", "HZO", "SM", "CNX", "CPG", "ATI", "CRS", "MTRN")

for (ticker in tickers) {
  try({
    getSymbols(ticker, src = "yahoo", auto.assign = TRUE)
    data <- get(ticker)
    if (is.null(data) || nrow(data) == 0) {
      next
    }
    chartSeries(data, subset='2023-05::2024-05', theme=chartTheme('white'), name = ticker)
    addBBands(n=20, sd=2)
    addRSI()
  }, silent = TRUE)
}
```

